def test_create_encounter_valid_timestamps(api_client, auth_token, patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{patient_id}"},
        "period": {
            "start": "2024-06-01T08:00:00Z",
            "end": "2024-06-01T09:00:00Z"
        }
    }
    resp = api_client.post(
        "/Encounter",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp.status_code == 201
    body = resp.json()
    assert "id" in body
    assert body["resourceType"] == "Encounter"

def test_create_encounter_end_before_start_rejected(api_client, auth_token, patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{patient_id}"},
        "period": {
            "start": "2024-06-01T09:00:00Z",
            "end": "2024-06-01T08:00:00Z"
        }
    }
    resp = api_client.post(
        "/Encounter",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp.status_code == 422
    body = resp.json()
    issues = body.get("issue", body.get("detail", ""))
    assert issues, "Expected error details in response body"

def test_create_encounter_end_equals_start_boundary(api_client, auth_token, patient_id):
    ts = "2024-06-01T08:00:00Z"
    payload = {
        "resourceType": "Encounter",
        "status": "finished",
        "subject": {"reference": f"Patient/{patient_id}"},
        "period": {"start": ts, "end": ts}
    }
    resp = api_client.post(
        "/Encounter",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp.status_code == 201
    body = resp.json()
    assert "id" in body
    assert body["period"]["start"] == ts
    assert body["period"]["end"] == ts

